// WF_NICHE_VIABILITY — Validate payload, auth check, fetch all analyses + discovered channels.

const raw = $input.first().json;
const payload = raw.body || raw;
const headers = raw.headers || {};

// Auth check
const expectedToken = $env.DASHBOARD_API_TOKEN;
const authHeader = headers.authorization || headers.Authorization || '';
if (!authHeader || authHeader !== `Bearer ${expectedToken}`) {
  return [{ json: { success: false, error: 'Unauthorized', http_status: 401 } }];
}

const analysisGroupId = (payload.analysis_group_id || '').trim();
if (!analysisGroupId) {
  return [{ json: { success: false, error: 'analysis_group_id is required', http_status: 400 } }];
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

try {
  // Fetch all completed channel analyses for this group
  const analysesRes = await fetch(
    `${supabaseUrl}/rest/v1/channel_analyses?analysis_group_id=eq.${analysisGroupId}&status=eq.completed&select=*&order=analyzed_at.asc`,
    { method: 'GET', headers: sbHeaders }
  );
  if (!analysesRes.ok) {
    return [{ json: { success: false, error: `Failed to fetch analyses: HTTP ${analysesRes.status}`, http_status: 500 } }];
  }
  const analyses = await analysesRes.json();
  if (!Array.isArray(analyses) || analyses.length === 0) {
    return [{ json: { success: false, error: 'No completed channel analyses found for this group', http_status: 404 } }];
  }

  // Fetch all discovered channels for this group
  const discRes = await fetch(
    `${supabaseUrl}/rest/v1/discovered_channels?analysis_group_id=eq.${analysisGroupId}&select=*&order=discovery_rank.asc`,
    { method: 'GET', headers: sbHeaders }
  );
  const discovered = discRes.ok ? await discRes.json() : [];

  return [{ json: {
    success: true,
    analysis_group_id: analysisGroupId,
    analyses: analyses,
    discovered_channels: Array.isArray(discovered) ? discovered : [],
    channels_analyzed: analyses.length,
    http_status: 202
  } }];
} catch (e) {
  return [{ json: { success: false, error: `Exception: ${e.message}`, http_status: 500 } }];
}

// Gate: only continue if validation succeeded.
const data = $input.first().json;
if (!data.success) {
  return [];
}
return [{ json: data }];

// Aggregate data across ALL analyzed channels for viability assessment.

const data = $input.first().json;
const analyses = data.analyses || [];
const discovered = data.discovered_channels || [];

// Combined topic frequency map
const topicFreq = {};
for (const a of analyses) {
  for (const t of (a.primary_topics || [])) {
    const key = t.toLowerCase().trim();
    topicFreq[key] = (topicFreq[key] || 0) + 1;
  }
}
const topicLandscape = Object.entries(topicFreq)
  .sort((a, b) => b[1] - a[1])
  .map(([topic, count]) => ({ topic, channel_count: count }));

// All top videos across channels — identify niche-wide outliers
const allTopVideos = [];
for (const a of analyses) {
  const vids = a.top_videos || [];
  for (const v of vids.slice(0, 5)) {
    allTopVideos.push({
      channel: a.channel_name,
      title: v.title,
      views: v.views || 0,
      likes: v.likes || 0,
      outlier_score: v.outlier_score || 0,
      duration_seconds: v.duration_seconds || 0
    });
  }
}
allTopVideos.sort((a, b) => b.views - a.views);
const nicheOutliers = allTopVideos.slice(0, 20);

// Title patterns: dominant formulas
const allTitleFormulas = [];
const allEmotionalTriggers = [];
let totalTitleLen = 0;
let titleCount = 0;
for (const a of analyses) {
  const tp = a.title_patterns || {};
  if (tp.common_formulas) allTitleFormulas.push(...tp.common_formulas);
  if (tp.emotional_triggers) allEmotionalTriggers.push(...tp.emotional_triggers);
  if (tp.avg_title_length) { totalTitleLen += tp.avg_title_length; titleCount++; }
}

// Thumbnail patterns: visual DNA
const thumbnailStyles = [];
for (const a of analyses) {
  const th = a.thumbnail_patterns || {};
  if (th.inferred_style) thumbnailStyles.push({ channel: a.channel_name, style: th.inferred_style, text_usage: th.text_usage, face_likely: th.face_likely });
}

// Scripting depth: average word count, vocab level
const scriptingLevels = [];
for (const a of analyses) {
  const sd = a.scripting_depth || {};
  scriptingLevels.push({
    channel: a.channel_name,
    research_level: sd.estimated_research_level || 'unknown',
    narrative_structure: sd.narrative_structure || '',
    production_quality: sd.production_quality || 'unknown'
  });
}

// Strengths, weaknesses, blue ocean opportunities (combined)
const allStrengths = [];
const allWeaknesses = [];
const allBlueOcean = [];
for (const a of analyses) {
  if (a.strengths) allStrengths.push(...a.strengths.map(s => ({ channel: a.channel_name, strength: s })));
  if (a.weaknesses) allWeaknesses.push(...a.weaknesses.map(w => ({ channel: a.channel_name, weakness: w })));
  if (a.blue_ocean_opportunities) allBlueOcean.push(...a.blue_ocean_opportunities.map(b => ({ channel: a.channel_name, ...b })));
}

// Aggregate numbers
const totalSubscribers = analyses.reduce((s, a) => s + (a.subscriber_count || 0), 0);
const totalMonthlyViews = analyses.reduce((s, a) => s + (a.estimated_monthly_views || 0), 0);
const uploadFreqs = analyses.map(a => a.upload_frequency_days).filter(v => v != null && v > 0);
const avgUploadFreq = uploadFreqs.length
  ? Math.round((uploadFreqs.reduce((a, b) => a + b, 0) / uploadFreqs.length) * 10) / 10
  : null;

// Content saturation map (combined)
const saturationMap = [];
for (const a of analyses) {
  for (const s of (a.content_saturation_map || [])) {
    saturationMap.push({ ...s, source_channel: a.channel_name });
  }
}

// Posting schedule patterns
const postingSchedules = analyses.map(a => ({ channel: a.channel_name, schedule: a.posting_schedule })).filter(p => p.schedule);

const aggregated = {
  topic_landscape: topicLandscape,
  niche_outliers: nicheOutliers,
  title_formulas: [...new Set(allTitleFormulas)].slice(0, 15),
  emotional_triggers: [...new Set(allEmotionalTriggers)].slice(0, 10),
  avg_title_length: titleCount > 0 ? Math.round(totalTitleLen / titleCount) : null,
  thumbnail_styles: thumbnailStyles,
  scripting_levels: scriptingLevels,
  all_strengths: allStrengths,
  all_weaknesses: allWeaknesses,
  all_blue_ocean: allBlueOcean,
  content_saturation_map: saturationMap,
  posting_schedules: postingSchedules,
  total_subscribers: totalSubscribers,
  total_monthly_views: totalMonthlyViews,
  avg_upload_frequency_days: avgUploadFreq,
  channels_analyzed: analyses.length,
  channel_summaries: analyses.map(a => ({
    name: a.channel_name,
    subscribers: a.subscriber_count,
    monthly_views: a.estimated_monthly_views,
    growth: a.growth_trajectory,
    verdict: a.verdict,
    verdict_score: a.verdict_score,
    avg_views: a.avg_views_per_video,
    avg_duration_sec: a.avg_video_duration_seconds
  }))
};

return [{ json: {
  ...data,
  aggregated: aggregated,
  failed: false
} }];

// Send aggregated data to Claude Opus 4.6 for comprehensive niche viability assessment.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const analysisGroupId = data.analysis_group_id;
const agg = data.aggregated;
const anthropicKey = $env.ANTHROPIC_API_KEY;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

const systemPrompt = `You are a YouTube niche viability analyst. You assess whether a niche is worth entering based on monetization potential, audience demand, competition gaps, and entry difficulty. You score each factor 0-100 and provide a weighted total. You also identify defensible moat opportunities. Be specific, data-driven, and brutally honest. No generic advice.`;

// Build the user prompt with aggregated data
const channelBlock = (agg.channel_summaries || []).map((c, i) =>
  `${i + 1}. ${c.name} — ${(c.subscribers || 0).toLocaleString()} subs, ${(c.monthly_views || 0).toLocaleString()} monthly views, avg ${(c.avg_views || 0).toLocaleString()} views/video, growth: ${c.growth}, verdict: ${c.verdict} (${c.verdict_score}/100), avg duration: ${Math.round((c.avg_duration_sec || 0) / 60)}min`
).join('\n');

const topicBlock = (agg.topic_landscape || []).slice(0, 20).map(t =>
  `- "${t.topic}" (covered by ${t.channel_count} channels)`
).join('\n');

const outlierBlock = (agg.niche_outliers || []).slice(0, 10).map((v, i) =>
  `${i + 1}. [${v.channel}] "${v.title}" — ${(v.views || 0).toLocaleString()} views, outlier: ${v.outlier_score}x`
).join('\n');

const strengthsBlock = (agg.all_strengths || []).slice(0, 15).map(s => `- [${s.channel}] ${s.strength}`).join('\n');
const weaknessesBlock = (agg.all_weaknesses || []).slice(0, 15).map(w => `- [${w.channel}] ${w.weakness}`).join('\n');
const blueOceanBlock = (agg.all_blue_ocean || []).slice(0, 15).map(b => `- [${b.channel}] ${b.opportunity} (difficulty: ${b.difficulty})`).join('\n');

const satBlock = (agg.content_saturation_map || []).slice(0, 20).map(s =>
  `- "${s.topic}" — ${s.saturation} (${s.video_count_seen || '?'} videos seen, from ${s.source_channel})`
).join('\n');

const titleFormulas = (agg.title_formulas || []).map(f => `- ${f}`).join('\n');
const scriptBlock = (agg.scripting_levels || []).map(s =>
  `- ${s.channel}: research=${s.research_level}, quality=${s.production_quality}`
).join('\n');

const userPrompt = `Analyze this YouTube niche for viability. ${agg.channels_analyzed} channels were analyzed.

CHANNEL SUMMARIES:
${channelBlock}

AGGREGATE STATS:
- Total subscribers across niche: ${(agg.total_subscribers || 0).toLocaleString()}
- Total estimated monthly views: ${(agg.total_monthly_views || 0).toLocaleString()}
- Average upload frequency: every ${agg.avg_upload_frequency_days || '?'} days

TOPIC LANDSCAPE (by coverage frequency):
${topicBlock}

NICHE-WIDE OUTLIER VIDEOS (highest views):
${outlierBlock}

TITLE PATTERNS:
Common formulas: ${titleFormulas || 'none identified'}
Emotional triggers: ${(agg.emotional_triggers || []).join(', ') || 'none identified'}
Avg title length: ${agg.avg_title_length || '?'} chars

SCRIPTING/PRODUCTION DEPTH:
${scriptBlock}

STRENGTHS ACROSS CHANNELS:
${strengthsBlock}

WEAKNESSES ACROSS CHANNELS:
${weaknessesBlock}

BLUE OCEAN OPPORTUNITIES IDENTIFIED:
${blueOceanBlock}

CONTENT SATURATION MAP:
${satBlock}

Return ONLY valid JSON with these exact fields:
{
  "monetization_score": <0-100>,
  "monetization_reasoning": "why this score",
  "estimated_rpm_range": { "low": 5.0, "mid": 12.0, "high": 25.0 },
  "ad_category": "Finance/Tech/Education/etc",
  "sponsorship_potential": "high|medium|low|none",
  "audience_demand_score": <0-100>,
  "audience_demand_reasoning": "why this score",
  "competition_gap_score": <0-100>,
  "competition_gap_reasoning": "why this score",
  "entry_difficulty_score": <0-100>,
  "entry_difficulty_reasoning": "why this score (100 = very easy to enter, 0 = impossible)",
  "viability_score": <0-100>,
  "viability_verdict": "strong_opportunity|moderate_opportunity|weak_opportunity|avoid",
  "viability_reasoning": "2-3 sentences",
  "blue_ocean_opportunities": [
    { "topic": "...", "reasoning": "...", "demand": "high|medium|low", "saturation": "none|low|moderate|high", "suggested_angle": "...", "moat_defensibility": "high|medium|low" }
  ],
  "saturated_topics": ["topic1", "topic2"],
  "recommended_angle": "the strategic positioning",
  "recommended_content_pillars": ["pillar1", "pillar2", "pillar3", "pillar4", "pillar5"],
  "differentiation_strategy": "how to stand out",
  "moat_indicators": [
    { "indicator": "...", "defensibility": "high|medium|low", "reasoning": "..." }
  ],
  "revenue_projections": {
    "at_10k_subs": { "monthly_usd": 500, "reasoning": "..." },
    "at_50k_subs": { "monthly_usd": 3000, "reasoning": "..." },
    "at_100k_subs": { "monthly_usd": 8000, "reasoning": "..." }
  },
  "script_depth_targets": {
    "target_word_count": 18000,
    "vocabulary_level": "intermediate|advanced|expert",
    "explanation_depth": "surface|moderate|deep|expert",
    "reasoning": "..."
  },
  "topics_to_avoid": ["topic1", "topic2"],
  "recommended_topics": [
    { "topic": "...", "angle": "...", "demand": "high|medium|low", "suggested_title_formula": "..." }
  ],
  "audience_demographics": "description of likely audience",
  "audience_size_estimate": "small|medium|large|very_large"
}`;

// Call Claude with retry
const claudeStart = Date.now();
let claudeResult = null;
let lastErr = null;

for (let attempt = 1; attempt <= 4; attempt++) {
  try {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-opus-4-6',
        max_tokens: 8192,
        system: systemPrompt,
        messages: [{ role: 'user', content: userPrompt }]
      })
    });
    if (res.ok) {
      const body = await res.json();
      claudeResult = {
        text: body.content?.[0]?.text || '',
        input_tokens: body.usage?.input_tokens || 0,
        output_tokens: body.usage?.output_tokens || 0,
        attempts: attempt
      };
      break;
    }
    const errBody = await res.text();
    if (res.status === 429) await sleep(30000);
    lastErr = `HTTP ${res.status}: ${errBody.slice(0, 300)}`;
    if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
  } catch (e) { lastErr = e.message; }
  if (attempt < 4) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
}

const claudeDuration = Date.now() - claudeStart;

if (!claudeResult) {
  // Log failure
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: null, topic_id: null, stage: 'niche_viability',
        scene_number: null, action: 'claude_viability_analysis', status: 'error',
        duration_ms: claudeDuration, cost_usd: 0, retry_count: 3
      })
    });
  } catch (_) {}
  return [{ json: { ...data, failed: true, error: `Claude analysis failed: ${lastErr}` } }];
}

// Parse Claude response
let parsed = null;
try {
  const clean = claudeResult.text.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch {
  const m = claudeResult.text.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch {} }
}

if (!parsed) {
  return [{ json: { ...data, failed: true, error: 'Claude response could not be parsed as JSON' } }];
}

// Cost: Opus 4.6 $15/M input, $75/M output
const costUsd = Math.round(((claudeResult.input_tokens * 15 + claudeResult.output_tokens * 75) / 1_000_000) * 10000) / 10000;

// Log success
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: null, topic_id: null, stage: 'niche_viability',
      scene_number: null, action: 'claude_viability_analysis', status: 'success',
      duration_ms: claudeDuration, cost_usd: costUsd, retry_count: (claudeResult.attempts || 1) - 1
    })
  });
} catch (_) {}

return [{ json: {
  ...data,
  claude_viability: parsed,
  analysis_cost_usd: costUsd,
  analysis_duration_ms: claudeDuration,
  input_tokens: claudeResult.input_tokens,
  output_tokens: claudeResult.output_tokens,
  failed: false
} }];

// Authoritative recomputation of viability_score from 4 sub-scores.
// Do NOT trust Claude's self-reported viability_score.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const cv = data.claude_viability;

// Clamp each sub-score to [0, 100]
function clamp(val) {
  const n = typeof val === 'number' ? val : parseInt(val, 10);
  if (isNaN(n)) return 50;
  return Math.max(0, Math.min(100, Math.round(n)));
}

const monetization = clamp(cv.monetization_score);
const demand = clamp(cv.audience_demand_score);
const gap = clamp(cv.competition_gap_score);
const difficulty = clamp(cv.entry_difficulty_score);

// Weighted: monetization 30%, demand 25%, gap 25%, difficulty 20%
const viabilityScore = Math.round(
  monetization * 0.30 +
  demand * 0.25 +
  gap * 0.25 +
  difficulty * 0.20
);
const clampedScore = Math.max(0, Math.min(100, viabilityScore));

// Map to verdict
let verdict;
if (clampedScore >= 75) verdict = 'strong_opportunity';
else if (clampedScore >= 50) verdict = 'moderate_opportunity';
else if (clampedScore >= 25) verdict = 'weak_opportunity';
else verdict = 'avoid';

// Extract RPM estimates
const rpmRange = cv.estimated_rpm_range || {};

return [{ json: {
  ...data,
  final_scores: {
    monetization_score: monetization,
    audience_demand_score: demand,
    competition_gap_score: gap,
    entry_difficulty_score: difficulty,
    viability_score: clampedScore,
    viability_verdict: verdict
  },
  rpm_estimates: {
    low: rpmRange.low || null,
    mid: rpmRange.mid || null,
    high: rpmRange.high || null
  },
  failed: false
} }];

// Write niche viability report to Supabase.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const cv = data.claude_viability;
const fs = data.final_scores;
const agg = data.aggregated;
const rpm = data.rpm_estimates;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Extract title_dna_patterns from aggregated data
const titleDna = {
  common_formulas: agg.title_formulas || [],
  emotional_triggers: agg.emotional_triggers || [],
  avg_title_length: agg.avg_title_length
};

// Extract thumbnail_dna_patterns from aggregated data
const thumbnailDna = agg.thumbnail_styles || [];

// Posting frequency benchmark
const postingBenchmark = agg.avg_upload_frequency_days
  ? `Every ${agg.avg_upload_frequency_days} days (niche average)`
  : null;

const report = {
  analysis_group_id: data.analysis_group_id,
  project_id: null,
  channels_analyzed: data.channels_analyzed,
  total_subscribers: agg.total_subscribers || 0,
  total_monthly_views: agg.total_monthly_views || 0,

  viability_score: fs.viability_score,
  viability_verdict: fs.viability_verdict,
  viability_reasoning: cv.viability_reasoning || null,

  monetization_score: fs.monetization_score,
  monetization_breakdown: {
    reasoning: cv.monetization_reasoning || null,
    ad_category: cv.ad_category || null,
    sponsorship_potential: cv.sponsorship_potential || null
  },
  audience_demand_score: fs.audience_demand_score,
  audience_demand_breakdown: {
    reasoning: cv.audience_demand_reasoning || null
  },
  competition_gap_score: fs.competition_gap_score,
  competition_gap_breakdown: {
    reasoning: cv.competition_gap_reasoning || null
  },
  entry_difficulty_score: fs.entry_difficulty_score,
  entry_difficulty_breakdown: {
    reasoning: cv.entry_difficulty_reasoning || null
  },

  estimated_rpm_low: rpm.low,
  estimated_rpm_mid: rpm.mid,
  estimated_rpm_high: rpm.high,
  ad_category: cv.ad_category || null,
  sponsorship_potential: cv.sponsorship_potential || null,

  blue_ocean_opportunities: cv.blue_ocean_opportunities || [],
  saturated_topics: cv.saturated_topics || [],
  recommended_angle: cv.recommended_angle || null,
  recommended_content_pillars: cv.recommended_content_pillars || [],
  differentiation_strategy: cv.differentiation_strategy || null,

  moat_indicators: cv.moat_indicators || null,
  defensibility_assessment: (cv.moat_indicators || []).length > 0
    ? cv.moat_indicators.filter(m => m.defensibility === 'high').length >= 2 ? 'strong' : 'moderate'
    : null,

  revenue_projections: cv.revenue_projections || null,

  audience_size_estimate: cv.audience_size_estimate || null,
  engagement_benchmarks: {
    channel_summaries: agg.channel_summaries || []
  },
  audience_demographics: cv.audience_demographics || null,

  script_depth_targets: cv.script_depth_targets || null,
  title_dna_patterns: titleDna,
  thumbnail_dna_patterns: thumbnailDna,
  posting_frequency_benchmark: postingBenchmark,

  topics_to_avoid: cv.topics_to_avoid || [],
  recommended_topics: cv.recommended_topics || [],

  analysis_cost_usd: data.analysis_cost_usd || 0
};

try {
  const res = await fetch(`${supabaseUrl}/rest/v1/niche_viability_reports`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=representation' },
    body: JSON.stringify(report)
  });
  if (!res.ok) {
    const errText = await res.text();
    return [{ json: { ...data, failed: true, error: `Write report failed: HTTP ${res.status}: ${errText.slice(0, 300)}` } }];
  }
  const rows = await res.json();
  const reportRow = Array.isArray(rows) && rows[0] ? rows[0] : null;

  return [{ json: {
    ...data,
    report_id: reportRow?.id || null,
    failed: false
  } }];
} catch (e) {
  return [{ json: { ...data, failed: true, error: `Exception writing report: ${e.message}` } }];
}

// Update all channel_analyses in the group with viability report reference.
// Also update the analysis group status (via a tag on each analysis row).

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const analysisGroupId = data.analysis_group_id;
const reportId = data.report_id;
const fs = data.final_scores;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// PATCH all completed analyses in this group — no viability_report_id column exists
// on channel_analyses, so we skip that. Instead we just note the group is done.
// The dashboard reads niche_viability_reports by analysis_group_id.

// If projects table has analysis_group_id column, check if a project links to this group
try {
  const projRes = await fetch(
    `${supabaseUrl}/rest/v1/projects?analysis_group_id=eq.${analysisGroupId}&select=id`,
    { method: 'GET', headers: sbHeaders }
  );
  if (projRes.ok) {
    const projects = await projRes.json();
    if (Array.isArray(projects)) {
      for (const proj of projects) {
        // Update project with viability data for downstream injection
        await fetch(`${supabaseUrl}/rest/v1/projects?id=eq.${proj.id}`, {
          method: 'PATCH',
          headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
          body: JSON.stringify({
            niche_viability_score: fs.viability_score,
            niche_viability_verdict: fs.viability_verdict
          })
        });
      }
    }
  }
} catch (_) {}

// Also update the niche_viability_reports.project_id if we found a project
try {
  const projRes2 = await fetch(
    `${supabaseUrl}/rest/v1/projects?analysis_group_id=eq.${analysisGroupId}&select=id&limit=1`,
    { method: 'GET', headers: sbHeaders }
  );
  if (projRes2.ok) {
    const projs = await projRes2.json();
    if (Array.isArray(projs) && projs.length > 0 && reportId) {
      await fetch(`${supabaseUrl}/rest/v1/niche_viability_reports?id=eq.${reportId}`, {
        method: 'PATCH',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({ project_id: projs[0].id })
      });
    }
  }
} catch (_) {}

return [{ json: {
  ...data,
  updates_applied: true,
  failed: false
} }];

// Log niche viability completion to production_logs.

const data = $input.first().json;
const fs = data.final_scores || {};

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: null,
      topic_id: null,
      stage: 'niche_viability',
      scene_number: null,
      action: 'viability_completed',
      status: 'success',
      duration_ms: data.analysis_duration_ms || 0,
      cost_usd: data.analysis_cost_usd || 0,
      retry_count: 0,
      details: JSON.stringify({
        analysis_group_id: data.analysis_group_id,
        report_id: data.report_id,
        channels_analyzed: data.channels_analyzed,
        viability_score: fs.viability_score,
        viability_verdict: fs.viability_verdict,
        monetization_score: fs.monetization_score,
        demand_score: fs.audience_demand_score,
        gap_score: fs.competition_gap_score,
        difficulty_score: fs.entry_difficulty_score
      })
    })
  });
} catch (_) {}

return [{ json: {
  success: true,
  analysis_group_id: data.analysis_group_id,
  report_id: data.report_id,
  viability_score: fs.viability_score,
  viability_verdict: fs.viability_verdict,
  channels_analyzed: data.channels_analyzed,
  cost_usd: data.analysis_cost_usd
} }];
